def _run_command(command, cwd=None, check=True, capture_output=False, env=None):
    """
    Helper to run shell commands.

    Args:
        command (list): The command and its arguments as a list.
        cwd (str, optional): The current working directory to run the command in. Defaults to None.
        check (bool, optional): If True, raise an exception for non-zero exit codes. Defaults to True.
        capture_output (bool, optional): If True, capture stdout/stderr. Defaults to False.
        env (dict, optional): Environment variables to pass. Defaults to None.

    Returns:
        subprocess.CompletedProcess: The result of the command execution.
    """
    print(f"Executing: {' '.join(command)}")
    try:
        result = subprocess.run(
            command,
            cwd=cwd,
            check=check,
            capture_output=capture_output,
            text=True,
            env=env
        )
        if capture_output:
            if result.stdout:
                print(result.stdout.strip())
            if result.stderr:
                print(result.stderr.strip(), file=sys.stderr)
        return result
    except subprocess.CalledProcessError as e:
        print(f"Error executing command: {' '.join(command)}", file=sys.stderr)
        if e.stdout:
            print(f"Stdout:\n{e.stdout}", file=sys.stderr)
        if e.stderr:
            print(f"Stderr:\n{e.stderr}", file=sys.stderr)
        sys.exit(e.returncode)
    except FileNotFoundError:
        print(f"Error: Command not found. Is '{command[0]}' installed and in your PATH?", file=sys.stderr)
        sys.exit(1)

def _is_poetry_project():
    """Checks if pyproject.toml exists and has a [tool.poetry] section."""
    pyproject_path = Path(POETRY_PYPROJECT_TOML)
    if not pyproject_path.exists():
        return False
    try:
        data = toml.load(pyproject_path)
        return "tool" in data and "poetry" in data["tool"]
    except Exception as e:
        print(f"Warning: Could not parse {POETRY_PYPROJECT_TOML}: {e}", file=sys.stderr)
        return False

def _is_pip_tools_project():
    """Checks if requirements.in exists."""
    return Path(PIP_TOOLS_REQUIREMENTS_IN).exists()

